public void postLoad()
{
    super();

    this.ReferenceTableName = tableId2Name(this.FWFTextBlockInstance_RefTableId);

    switch (this.FWFTextBlockInstance_RefTableId)
    {
        case tableNum(SalesTable):
            this.ReferenceId = SalesTable::findRecId(this.FWFTextBlockInstance_RefRecId).SalesId;
            break;

        case tableNum(SalesLine):
            SalesLine salesLine = SalesLine::findRecId(this.FWFTextBlockInstance_RefRecId);
            this.ReferenceId = salesLine.SalesId;
            this.LineNum = salesLine.LineNum;
            break;

        case tableNum(ProdTable):
            this.ReferenceId = ProdTable::findRecId(this.FWFTextBlockInstance_RefRecId).ProdId;
            break;

        case tableNum(PurchTable):
            this.ReferenceId = PurchTable::findRecId(this.FWFTextBlockInstance_RefRecId).PurchId;
            break;

        case tableNum(PurchLine):
            PurchLine purchLine = PurchLine::findRecId(this.FWFTextBlockInstance_RefRecId);
            this.ReferenceId = purchLine.PurchId;
            this.LineNum = purchLine.LineNumber;
            break;
    }
}

/// <summary>
///
/// </summary>
/// <param name = "_entityCtx"></param>
/// <param name = "_dataSourceCtx"></param>
/// <returns></returns>
public boolean insertEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    boolean                 ret;
    FWFTextBlockValueEntity textBlockValueEntity;
    FWFTextBlockValue       textBlockValue;
    Notes                   origText;

    if (_dataSourceCtx.name() == dataEntityDataSourceStr(FWFTextBlockValueEntity, FWFTextBlockValue))
    {
        textBlockValueEntity = _entityCtx.getEntityRecord();
        textBlockValue = FWFTextBlockValue::find(textBlockValueEntity.FWFTextBlockInstance_ValueRecId);
        origText = textBlockValue.TextBlock;
    }

    ret = super(_entityCtx, _dataSourceCtx);

    if (_dataSourceCtx.name() == dataEntityDataSourceStr(FWFTextBlockValueEntity, FWFTextBlockValue))
    {
        textBlockValue = _dataSourceCtx.getBuffer();
        if (textBlockValue.TextBlock != origText)
        {
            textBlockValue.selectForUpdate(true);
            textBlockValue.TextBlock = origText;
            textBlockValue.update();
        }
    }

    if (_dataSourceCtx.name() == dataEntityDataSourceStr(FWFTextBlockValueEntity, FWFTextBlockInstance))
    {
        this.insertUpdateTextBlockValue(_entityCtx, _dataSourceCtx);
    }

    return ret;
}

/// <summary>
///
